mapper.select:
select s.id as s_id , s.host_id , s.title , s.description , s.address , s.price_per_hour , s.capacity , si.id as si_id , si.space_id , si.image_url , si.is_main from space s left join space_image si on s.id = si.space_id and si.is_main = 1 and si.is_deleted = 0 where s.is_deleted = 0
and (s.title like concat('%', #{keyword}, '%') or s.address like concat('%', #{keyword}, '%'))
order by s.id desc limit #{limit} offset #{offset}

mapper.update:
update space
set title = #{title}
    ,description = #{description}
    ,address = #{address}
    ,price_per_hour = #{pricePerHour}
    ,capacity = #{capacity}
where id = #{id}

update space
set is_deleted = 1
where id = #{spaceId}
